insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 0, '关于数据与信息的关系，下列说法正确的是？', '数据本身就是信息', '信息是数据的载体，数据是信息的表达', '信息是向人们提供现实世界新事实的依据，来源于数据', '数据蕴涵的信息会自动呈现出来', 'C', '数据是未经加工的原始资料，是客观对象的表示，其本身并不是信息。信息来源于数据，是数据内涵的意义和对数据内容的解释。数据蕴涵的信息不会自动呈现出来，需要利用技术对其解释。信息是数据的表达，数据是信息的载体。因此，C项表述正确。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 1, '地理实体和地理现象的数据描述标准通常不包括以下哪一部分？', '空间位置数据', '拓扑结构编码', '属性数据', '时域数据', 'B', '地理对象或地理现象的数据描述包括空间位置、属性数据（简称属性）及时域数据三部分。虽然拓扑关系是空间数据的一种类型，但在宏观描述地理数据的三大核心构成时，标准术语为空间位置、属性数据和时域数据。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 2, '“在不同地方或区域上，地理数据的变化趋势是不同的”，这句话深刻体现了地理信息的哪种独特特性？', '空间相关性', '空间区域性', '空间多样性', '空间层次性', 'C', '空间多样性指在不同地方或区域上，地理数据的变化趋势是不同的，这意味着地理信息的分析结果需要依赖于其位置，才能得出合乎逻辑的解释。空间相关性强调距离越近相关性越大；区域性强调天然的分区组织特征；层次性强调多重属性或空间尺度。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 3, '如果根据应用层次对信息系统进行分类，地理信息系统（GIS）属于下列哪种系统？', '事务处理系统', '空间信息系统', '决策支持系统', '管理信息系统', 'C', '在应用层次上，信息系统有事务处理系统、管理信息系统、决策支持系统等系统。地理信息系统在处理对象上属空间信息系统，而在应用层次上则属决策支持系统。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 4, 'GIS区别于其它类型普通信息系统的根本标志在于？', '具有海量数据的压缩管理能力', '能够进行复杂的跨表属性查询', '每一个数据都按统一的地理坐标进行编码，实现定位、定性和定量的描述', '采用了最先进的云计算与并行计算技术', 'C', '空间数据的最根本特点是每一个数据都按统一的地理坐标进行编码，实现对其定位、定性和定量的描述，这是GIS区别于其它类型信息系统的根本标志，也是其技术难点之所在。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 5, '在学术界，GIS常被誉为“地学的第三代语言”，这主要是因为它？', '是地理科学第二次革命的主要工具', '能够用数字形式来描述空间实体', '完美结合了测绘学和遥感技术', '拥有最复杂的拓扑查询语言', 'B', 'GIS被誉为地学的第三代语言，其核心含义是指它能够用数字形式来描述空间实体。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 6, '在GIS发展历程中，其简称“GIS”中的“S”含义经历了显著演变。当它代表人们日常生活中的大众化应用（如导航软件）时，这个“S”代表的是？', 'System（系统）', 'Science（科学）', 'Service（服务）', 'Society（社会）', 'C', '随着互联网技术、计算机技术的普及，地理信息系统已经从单纯的技术型和研究型逐步向地理信息服务层面转移，在这一层面上，“S”一词代表着服务（Service）。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 7, '在GIS系统的五大组成部分中，被形容为GIS的“血液”的是？', '计算机硬件', '软件系统', '地学模型', '空间数据', 'D', '数据是GIS的核心内容，贯穿于GIS的各个过程，有人将它称之为GIS的血液。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 8, '在GIS的各个组成部分中，最为关键和具有能动性因素的是哪一项？', '处理海量数据的服务器', '高效的空间数据库', '管理与应用人员', '用于空间分析的地学模型', 'C', '人是GIS中的重要构成因素。人员是系统建设中的关键和能动性因素，直接影响和协调其它几个组成部分。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 9, '为了解决特定行业复杂的业务问题（如河网提取），GIS引入了哪一组成部分来提供具体的解决方案？', '关系型数据库系统', '地学模型', '全站仪和GPS设备', '操作系统底座', 'B', '模型为GIS应用提供解决方案。地学模型是根据具体的地学目标和问题，以GIS已有的操作和方法为基础，构建能够表达或模拟特定现象的计算机模型。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 10, '空间数据包括三种互相联系的数据类型，用来表示点、线、面实体之间（如相邻、包含）空间联系的数据属于？', '空间位置数据（几何坐标）', '空间关系数据（拓扑关系）', '属性数据（非几何属性）', '时态数据序列', 'B', '实体间的空间相关性即拓扑关系，表示点、线、面实体之间的空间联系，如边界线与面实体间的构成关系，面实体与内部点的包含关系等。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 11, '在GIS软件系统中，像Windows、Linux这样的操作系统，以及Oracle等大型数据库管理系统，被统一归类为？', 'GIS应用软件', 'GIS平台软件', 'GIS支撑软件', 'GIS功能组件包', 'C', 'GIS支撑软件是指GIS运行所必需的各种软件环境，如操作系统、数据库管理系统、图形处理系统等。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 12, '教材中常将“GIS空间分析”与“GIS应用分析”的关系生动地比喻为？', '“血液”与“躯体”', '“零件”与“机器”', '“骨骼”与“肌肉”', '“软件”与“硬件”', 'B', 'GIS空间分析为建立和解决复杂的应用模型提供了基本工具，因此GIS空间分析和应用分析是“零件”和“机器”的关系。用户应用GIS解决实际问题的关键，就是如何将这些零件搭配成解决问题的“机器”。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 13, 'GIS可以求解五个基本问题。当需要根据历史数据对地貌未来的发育演变进行分析判断时，这解答的是哪类基本问题？', '位置问题', '条件问题', '趋势问题', '模式问题', 'C', '趋势问题探讨某个地方发生的某个事件及其随时间的变化过程，要求GIS能够对现象的变化过程做出分析判断，并能对未来做出预测和对过去做出回溯。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 14, '由于原始空间数据不可避免含有误差，为了保证数据在一致性和完整性上的逻辑正确，GIS必须具备以下哪种功能？', '数据采集功能', '数据编辑与处理功能', '空间查询功能', '数据可视化输出功能', 'B', '为保证数据在内容、逻辑、数值上的一致性和完整性，需要对数据进行编辑、格式转换、拼接等一系列的处理工作，包括图形编辑、拓扑建立等，这属于数据编辑与处理功能。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 15, '关于空间数据的组织与管理，下列说法中正确的是？', '一般信息系统的数据结构完全适合直接管理空间数据', '所有的GIS空间数据仅能通过栅格数据结构来存储', '目前有些GIS的图形数据也开始交给扩展了空间功能的商用关系数据库管理系统管理', '空间数据必须与属性数据物理隔离，互不关联', 'C', '一般信息系统的数据结构和数据库管理系统并不适合管理空间数据。但目前随着技术发展，有些GIS的图形数据也交给关系数据库管理系统管理，且关系数据库管理系统也在向空间数据管理方面扩展（如Oracle等）。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 16, '作为GIS的分析理论基础，可为GIS提供引导空间分析的方法和观点的学科是？', '计算机科学', '地图制图学', '地理学', '测量学', 'C', '地理学是GIS的分析理论基础，可为GIS提供引导空间分析的方法和观点。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 17, 'GIS系统与普通关系数据库管理系统（DBMS）的主要区别体现在？', 'DBMS只能存储图片，不能存储文字', 'GIS不仅需要数据管理功能，还需要具有图形数据的采集、可视化和空间分析功能', 'DBMS运行速度永远比GIS慢', 'GIS只处理单一定长的字符串数据', 'B', '地理信息系统除需要功能强大的空间数据的管理功能之外，还需要具有图形数据的采集、空间数据的可视化和空间分析等功能，在功能和软硬件方面比一般事务数据库更复杂。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 18, '许多工程人员将计算机辅助设计（CAD）作为数字制图工具。与GIS相比，CAD系统存在的主要局限性是？', 'CAD无法处理规则的几何图形', 'CAD没有坐标参考系统', 'CAD属性功能相对较弱，空间分析能力和海量图库管理能力较弱', 'CAD无法进行任何数据的输出', 'C', 'CAD处理的多为规则几何图形，图形功能极强，但属性功能相对较弱。而GIS处理多为复杂的自然与人工目标，具有丰富的属性库和极强的空间分析功能，同时CAD一般仅在单幅图上操作，海量数据的图库管理能力较弱。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 19, '遥感（RS）技术在地理信息系统体系中扮演的最主要角色是？', '提供所有的拓扑空间分析算法', '作为数据库底层的操作系统软件', '为GIS的数据更新提供丰富、实时、可靠和廉价的多种信息源', '替代GIS直接进行社会经济人口数据的统计与可视化', 'C', '测绘学和遥感技术不但为GIS提供快速、可靠、多时相和廉价的多种信息源，而且其获取的影像常进入GIS系统作为背景影像或协同集成分析。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 20, '在20世纪60年代的GIS开拓期，严重制约地理信息系统图形和地学分析功能发展的客观瓶颈是？', '缺乏地学理论的引导', '测绘人员的数据采集意愿低', '计算机硬件存储能力小且磁带存取速度极慢', '没有任何面向部门的专业需求', 'C', '在20世纪60年代的开拓起步阶段，计算机硬件系统的功能还很弱，计算机存储能力很小且磁带存取速度也很慢，极大地制约着地理信息系统的发展。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 21, '在GIS技术的巩固发展期（20世纪70年代），GIS软件技术取得的最重要的进展标志是？', '人机图形交互技术的发展', '云计算平台的搭建', '自动人工智能影像识别', '移动互联网定位的突破', 'A', '在20世纪70年代，由于图形、图像卡等技术的发展增强了人机对话和显示功能，人机图形交互技术的发展成为这一时期软件的最重要进展。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 22, '1998年由美国副总统戈尔提出的，核心思想是用数字化手段统一处理地球问题并嵌入海量多分辨率数据的标志性概念是？', '物联网GIS', '数字地球', '虚拟现实地球', '智慧城市网格', 'B', '1998年美国副总统戈尔提出“数字地球”的概念，其核心思想是用数字化手段统一处理地球问题和最大限度地利用信息资源。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 23, '被称为第三代互联网应用，能够把分布的计算机集群集成在一起，实现空间信息分布式、协作化和智能化处理的技术是？', '网格GIS（Grid GIS）', '移动GIS（Mobile GIS）', '时态GIS（Temporal GIS）', '互操作GIS（Interoperable GIS）', 'A', '网格(Grid)被称为第三代互联网应用，它是把整个互联网整合成一台巨大的超级计算机，基于网格计算的GIS平台，能够分布式、协作化和智能化地处理地理信息。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 24, '能够提供“4A服务”（在任何时间、任何地点为任何人、任何事服务），例如个人位置服务和车辆导航定位的技术形态是？', 'VR GIS', '云 GIS', '移动 GIS', '并行 GIS', 'C', '无线通信技术、移动定位技术和WebGIS的结合形成了移动GIS，它可以使地理信息随时、随地、为任何人、任何事进行服务（4A服务）。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 25, '在现代“智慧城市”中，能够通过大量装载在对象上的传感器实时获取动态属性与位置信息，从而极大扩展GIS底层感知网络的技术是？', '计算机辅助设计(CAD)', '虚拟建模语言(VRML)', '传统纸质地图扫描', '物联网(IoT)', 'D', '物联网通过装载在物联对象上的传感器实时、动态地获取信息，这些物联网产生的数据都带有位置和时间信息，促进了GIS的发展并为城市空间物联信息的应用提供基础。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 26, '面临企业级应用海量多源数据的压力，目前改变了计算机为用户提供服务的模式，使得“托管的不再是客户本地设备，而是云端的计算能力”的技术是？', '桌面端个人关系型数据库', '移动单机导航软件', '云计算与云数据中心', '机助制图系统', 'C', '云计算数据中心改变了计算机为用户提供服务的模式，云数据中心中托管的不再是客户的设备，而是计算能力和可用性的各项功能。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 27, '传统的GIS数据管理技术无法应对现今多源、异构的时空大数据。为解决这一难题，在数据处理和分析环节广泛引入的成熟方案是？', '增加单机的机械硬盘存储', '退回使用手工记录表格', '采用基于Hadoop和Spark等架构的并行计算技术', '仅使用关系型数据库单线程查询', 'C', '时空大数据处理与分析是大数据GIS的核心内容，目前基于 Hadoop 和 Spark 等并行计算技术的空间数据处理与管理，是较为成熟并广泛使用的方案之一。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 28, '在处理复杂的时空大数据挖掘时，传统的数据分析难以发现隐含规律。现代GIS正逐步引入哪种前沿算法，使其能够通过自调试参数实现“自我学习”和准确预测？', '静态几何量算', '固定条件筛选语言 (SQL)', '机器学习与人工智能', '人工拓扑查错', 'C', '机器学习的算法不是固定的，而是带有自调试参数，能够随着分析内容和频次的增加，让计算机通过学习自我完善，使挖掘和预测的结果更准确。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-1', 29, '公安部门通过分析特定城市内犯罪几率与该市酒吧、交通、照明等元素的耦合关系，以此提炼出能推广到其他城市的犯罪预警模型。这最主要体现了GIS解决的哪类基本问题？', '位置问题 (Location)', '趋势问题 (Trend)', '模拟问题 (Simulation)', '条件问题 (Condition)', 'C', '模拟即某个地方如果具备某种条件会发生什么问题，是在模式和趋势的基础上，建立现象和因素之间的模型关系。例如研究犯罪几率和周边因素分布的耦合关系，建立通用模型进行未来预测决策。', datetime('now'));
